-- ============================================
-- Legislacao full-site: renan-filho / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/160623
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = renan-filho-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 68
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=160623, tipo Deputado(a), ordemAssinatura=1.
-- 32 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'renan-filho';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'renan-filho: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao renan-filho: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('523141', '521288', '514289', '514334', '504540', '504539', '610702', '600168', '580438', '858737', '612576', '610173', '562366', '559300', '557078', '553225', '549869', '610703', '600169', '564035', '559853', '557479', '555698', '549854', '619499', '611386', '600639', '571411', '560046', '558568', '555714', '551929', '549856', '520766', '517929', '509326', '504538', '611987', '610172', '561784', '559299', '555743', '553224', '549868', '545666', '527615', '562368', '557477', '555193', '549870', '514352', '504541', '504536', '499490', '496204', '520518', '514532', '508793', '504537', '502272', '496206', '504535', '498024', '504534', '497877', '504533', '497871', '559511');
  IF target_present <> 68 THEN
    RAISE EXCEPTION 'Pre-condicao renan-filho: esperadas 68 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('523141', '521288', '514289', '514334', '504540', '504539', '610702', '600168', '580438', '858737', '612576', '610173', '562366', '559300', '557078', '553225', '549869', '610703', '600169', '564035', '559853', '557479', '555698', '549854', '619499', '611386', '600639', '571411', '560046', '558568', '555714', '551929', '549856', '520766', '517929', '509326', '504538', '611987', '610172', '561784', '559299', '555743', '553224', '549868', '545666', '527615', '562368', '557477', '555193', '549870', '514352', '504541', '504536', '499490', '496204', '520518', '514532', '508793', '504537', '502272', '496206', '504535', '498024', '504534', '497877', '504533', '497871', '559511')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'renan-filho-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao renan-filho: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao renan-filho: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

